using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_9065f3f20f5d4c4d8983395402505fde.Components;

public class CustomValidator : ComponentBase
{
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_9065f3f20f5d4c4d8983395402505fde.Services
@inject IAppointmentService AppointmentService

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    <h2>Step 1: Patient Information</h2>

    <div class="mb-3">
        <label class="form-label">Patient Name</label>
        <InputText class="form-control" @bind-Value="model.PatientName" />
        <ValidationMessage For="() => model.PatientName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="model.Email" />
        <ValidationMessage For="() => model.Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="model.Phone" />
        <ValidationMessage For="() => model.Phone" />
    </div>

    <div class="mb-3">
        <label class="form-label">Insurance Provider</label>
        <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
            <option value="">-- Select --</option>
            <option value="Aetna">Aetna</option>
            <option value="BlueCross">BlueCross</option>
            <option value="Cigna">Cigna</option>
            <option value="UnitedHealth">UnitedHealth</option>
            <option value="None">None</option>
        </InputSelect>
        <ValidationMessage For="() => model.InsuranceProvider" />
    </div>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next
        </button>
    }

    @if (showStep2)
    {
        <h2>Step 2: Appointment Details</h2>

        <div class="mb-3">
            <label class="form-label">Preferred Doctor</label>
            <InputSelect class="form-select" @bind-Value="model.PreferredDoctor">
                <option value="">-- Select --</option>
                @foreach (var doctor in doctors)
                {
                    <option value="@doctor">@doctor</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.PreferredDoctor" />
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="model.AppointmentDate" @bind:after="OnDateChanged" />
            <ValidationMessage For="() => model.AppointmentDate" />
        </div>

        <div class="mb-3">
            <label class="form-label">Time Slot</label>
            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => model.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="model.ReasonForVisit" rows="4" />
            <ValidationMessage For="() => model.ReasonForVisit" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability" disabled="@isChecking">
            @(isChecking ? "Checking..." : "Check Availability")
        </button>

        @if (availabilityConfirmed)
        {
            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Booking..." : "Book Appointment")
            </button>
        }
    }

    @if (bookingConfirmed)
    {
        <div class="alert alert-success mt-3">Appointment booked successfully!</div>
    }
</EditForm>

@code {
    private AppointmentFormModel model = new();
    private EditContext? editContext;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isChecking;
    private bool isSubmitting;
    private bool availabilityConfirmed;
    private bool bookingConfirmed;

    private List<string> doctors = new();
    private List<string> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step 1 fields
        var isValid = true;
        var step1Fields = new[] {
            nameof(AppointmentFormModel.PatientName),
            nameof(AppointmentFormModel.Email),
            nameof(AppointmentFormModel.Phone),
            nameof(AppointmentFormModel.InsuranceProvider)
        };

        foreach (var field in step1Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            editContext.NotifyFieldChanged(fieldIdentifier);
            if (editContext.GetValidationMessages(fieldIdentifier).Any())
            {
                isValid = false;
            }
        }

        if (isValid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDateChanged()
    {
        if (model.AppointmentDate.HasValue && !string.IsNullOrEmpty(model.PreferredDoctor))
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.PreferredDoctor, model.AppointmentDate.Value);
            model.TimeSlot = null;
            availabilityConfirmed = false;
        }
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityConfirmed = false;

        // Validate step 2 fields first
        var step2Valid = true;
        var step2Fields = new[] {
            nameof(AppointmentFormModel.PreferredDoctor),
            nameof(AppointmentFormModel.AppointmentDate),
            nameof(AppointmentFormModel.TimeSlot),
            nameof(AppointmentFormModel.ReasonForVisit)
        };

        foreach (var field in step2Fields)
        {
            var fieldIdentifier = editContext!.Field(field);
            editContext.NotifyFieldChanged(fieldIdentifier);
            if (editContext.GetValidationMessages(fieldIdentifier).Any())
            {
                step2Valid = false;
            }
        }

        // Check future date manually
        if (model.AppointmentDate.HasValue && model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            customValidator!.DisplayErrors(new Dictionary<string, List<string>>
            {
                [nameof(AppointmentFormModel.AppointmentDate)] = new() { "Date must be in the future." }
            });
            return;
        }

        if (!step2Valid) return;

        isChecking = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email ?? "",
                model.InsuranceProvider ?? "",
                model.PreferredDoctor ?? "",
                model.TimeSlot ?? "");

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
            }
            else
            {
                availabilityConfirmed = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityConfirmed) return;

        isSubmitting = true;
        try
        {
            var request = new AppointmentRequest
            {
                PatientName = model.PatientName!,
                Email = model.Email!,
                Phone = model.Phone!,
                InsuranceProvider = model.InsuranceProvider!,
                PreferredDoctor = model.PreferredDoctor!,
                AppointmentDate = model.AppointmentDate!.Value,
                TimeSlot = model.TimeSlot!,
                ReasonForVisit = model.ReasonForVisit!
            };

            var result = await AppointmentService.BookAppointmentAsync(request);
            bookingConfirmed = result;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

